local _SkillTab = {
	nForceID = 1,               -- 所属门派（-1为公共技能）
	szName = "悟·三环套月",     -- 技能名
	nIconID = 100003,           -- 技能图标
	szDesc = "",                -- 技能描述
	tbSkillEffectDesc = {       -- 技能通用效果描述
		{1,     "描述"},        -- {图标ID, 描述内容}
	},
	tbAttrib = {                -- 技能伤害描述
	},

	---@enum UISkillType 技能类型
	nType = 1,                  -- 技能类型（普攻=1，技能=2，奇穴=3，触发技=4，追加技=5）

	---@enum UISkillCastType 技能释放类型
	nCastType = 1,              -- 按键释放方式（抬手释放=1，按下释放=5，持续按住=2，连续点击=3，选择头像=4）

	------------------------------
	bJoystick = false,          -- 是否滑动选点释放（选了这项，["bJoystick"] = true   ["bCastXYZ"] = true， 导出）这一项与下面的“是否滑动指向释放”互斥      是否滑动指向释放（选了这项，["bJoystick"] = true   ["bCastXYZ"] = false， 导出）这一项与上面的“是否滑动选点释放”互斥
	bCastXYZ = false,
	------------------------------
	nPosture = 0,               -- 姿态（1、2、3    先预留3个可选）
	bForbidLevelUp = false,     -- 是否禁止升级
	fPressGuardTime = 0,        -- 持续按住的保护时间
	bForbidSelectTarget = false,-- 是否禁用技能索敌
	bAllyTarget = false,        -- 是否搜索友方作为目标（依赖"bForbidSelectTarget"==true)
	tbOrder = {                 -- 在技能列表中的排序
		1,  0                   -- 主技能、二段技能排序
	},
}

